import React, { useEffect, useRef, useState } from "react";
import "./EeshaWalkComponent.css";

// ── Tuning ────────────────────────────────────────────────────────────────────
const FREEZE_MS       = 2500;   // ms without step → freeze
const STEP_LEAD       = 1.10;   // metronome 10% faster than detected cadence
const RESCUE_LEAD     = 1.30;   // rescue beat 30% faster during freeze
const NORMAL_VOL      = 0.85;
const RESCUE_VOL      = 1.00;
const STEP_PAN        = 0.35;   // L/R pan per alternating beat
const MIN_STEP_MS     = 320;    // anti-bounce
const FAST_WIN        = 5;      // fast moving-average window
const SLOW_WIN        = 30;     // slow moving-average (noise floor)
const SENS_THRESHOLD  = 1.8;    // fast/slow ratio to detect a step
const DEFAULT_BPM     = 80;


// ── Audio buffer generation ───────────────────────────────────────────────────

function addForwardReverb(mono, sr) {
  // Bake early reflections into signal → "in front" through headphones
  const out = new Float32Array(mono);
  const reflections = [[0.0013, 0.12], [0.0029, 0.06], [0.0046, 0.03]];
  for (const [d, g] of reflections) {
    const offset = Math.round(d * sr);
    for (let i = offset; i < out.length; i++) out[i] += mono[i - offset] * g;
  }
  return out;
}

function applyPan(mono, pan) {
  // Equal-power law: pan ∈ [-1, 1], 0 = centre/forward
  const angle = (pan + 1) * Math.PI / 4;
  return { l: mono.map(v => v * Math.cos(angle)),
           r: mono.map(v => v * Math.sin(angle)) };
}

function buildBuffer(ctx, generator, pan, vol) {
  const sr   = ctx.sampleRate;
  const mono = generator(sr);
  const reverbed = addForwardReverb(mono, sr);
  const scaled = reverbed.map(v => v * vol);
  const { l, r } = applyPan(scaled, pan);
  const buf  = ctx.createBuffer(2, mono.length, sr);
  buf.getChannelData(0).set(l);
  buf.getChannelData(1).set(r);
  return buf;
}

// ADSR helper
function adsr(len, sr, atk, dec, sus, rel) {
  const env = new Float32Array(len).fill(sus);
  const a = Math.min(Math.round(atk * sr), len);
  const d = Math.min(Math.round(dec * sr), len - a);
  const r = Math.min(Math.round(rel * sr), len);
  const sEnd = len - r;
  for (let i = 0; i < a; i++)         env[i] = i / a;
  for (let i = 0; i < d; i++)         env[a + i] = 1 - (1 - sus) * (i / d);
  for (let i = sEnd; i < len; i++)    env[i] = sus * (1 - (i - sEnd) / r);
  return env;
}

// ── Sound generators (return Float32Array of mono samples) ───────────────────

function genClick(sr) {
  const dur = 0.06;
  const len = Math.round(sr * dur);
  const env = adsr(len, sr, 0.001, dur * 0.55, 0, dur * 0.45);
  const out = new Float32Array(len);
  for (let i = 0; i < len; i++) {
    const t = i / sr;
    out[i] = (Math.sin(2 * Math.PI * 1100 * t) * 0.6
            + (Math.random() * 2 - 1) * 0.4) * env[i];
  }
  const peak = Math.max(...out.map(Math.abs)) || 1;
  return out.map(v => v / peak);
}

function genWood(sr) {
  const dur = 0.09;
  const len = Math.round(sr * dur);
  const env = adsr(len, sr, 0.001, dur * 0.3, 0, dur * 0.7);
  const out = new Float32Array(len);
  for (let i = 0; i < len; i++) {
    const t = i / sr;
    out[i] = (Math.sin(2 * Math.PI * 900  * t) * 0.50
            + Math.sin(2 * Math.PI * 2484 * t) * 0.30
            + Math.sin(2 * Math.PI * 4860 * t) * 0.20) * env[i];
  }
  const peak = Math.max(...out.map(Math.abs)) || 1;
  return out.map(v => v / peak);
}

function genBell(sr) {
  const dur = 0.28;
  const len = Math.round(sr * dur);
  const env = adsr(len, sr, 0.003, dur * 0.1, 0.25, dur * 0.6);
  const out = new Float32Array(len);
  const partials = [[1.0, 1.0], [2.756, 0.45], [5.404, 0.2], [8.933, 0.08]];
  for (let i = 0; i < len; i++) {
    const t = i / sr;
    out[i] = partials.reduce((s, [r, a]) => s + a * Math.sin(2 * Math.PI * 523 * r * t), 0) * env[i];
  }
  const peak = Math.max(...out.map(Math.abs)) || 1;
  return out.map(v => v / peak);
}

function genBass(sr) {
  const dur = 0.16;
  const len = Math.round(sr * dur);
  const env = adsr(len, sr, 0.001, dur * 0.4, 0, dur * 0.6);
  const out = new Float32Array(len);
  let phase = 0;
  for (let i = 0; i < len; i++) {
    const t   = i / sr;
    const freq = 100 * Math.exp(-10 * t);     // pitch sweep down
    phase += (2 * Math.PI * freq) / sr;
    out[i] = (Math.sin(phase) * 0.85 + (Math.random() * 2 - 1) * 0.15) * env[i];
  }
  const peak = Math.max(...out.map(Math.abs)) || 1;
  return out.map(v => v / peak);
}

const GENERATORS = { click: genClick, wood: genWood, bell: genBell, bass: genBass };

function buildSoundSet(ctx, soundType) {
  const gen = GENERATORS[soundType] ?? genClick;
  return {
    left:   buildBuffer(ctx, gen,      -STEP_PAN, NORMAL_VOL),
    right:  buildBuffer(ctx, gen,      +STEP_PAN, NORMAL_VOL),
    rescue: buildBuffer(ctx, genClick,  0,         RESCUE_VOL),
  };
}

function playBuf(ctx, buf) {
  const src = ctx.createBufferSource();
  src.buffer = buf;
  src.connect(ctx.destination);
  src.start();
}


// ── Component ─────────────────────────────────────────────────────────────────

export default function EeshaWalkComponent({ audioCtx, soundType, onStop }) {
  const [bpm,      setBpm]      = useState("--");
  const [steps,    setSteps]    = useState(0);
  const [isFrozen, setIsFrozen] = useState(false);

  const e = useRef({
    isRunning:    true,
    sounds:       null,       // { left, right, rescue } AudioBuffers
    lastStepMs:   0,
    stepTimes:    [],         // last 5 step timestamps for BPM calc
    currentBPM:   DEFAULT_BPM,
    beatSide:     0,          // 0=left, 1=right
    fastWin:      [],
    slowWin:      [],
    above:        false,      // hysteresis flag
  });

  // Store motion handler in a ref so cleanup removes the exact same function
  const motionHandlerRef = useRef(null);

  useEffect(() => {
    const eng = e.current;
    eng.sounds = buildSoundSet(audioCtx, soundType);

    const init = async () => {
      // iOS 13+ requires explicit permission for DeviceMotion
      if (typeof DeviceMotionEvent?.requestPermission === "function") {
        const res = await DeviceMotionEvent.requestPermission();
        if (res !== "granted") { onStop(); return; }
      }

      motionHandlerRef.current = handleMotion;
      window.addEventListener("devicemotion", motionHandlerRef.current);
      scheduleBeat();
    };

    init();

    return () => {
      eng.isRunning = false;
      if (motionHandlerRef.current) {
        window.removeEventListener("devicemotion", motionHandlerRef.current);
      }
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // ── Step detection (dual moving-average) ───────────────────────────────────
  const handleMotion = (e_) => {
    const acc = e_.acceleration || e_.accelerationIncludingGravity;
    if (!acc) return;

    // Use magnitude of all axes so phone orientation doesn't matter
    const mag = Math.sqrt((acc.x ?? 0) ** 2 + (acc.y ?? 0) ** 2 + (acc.z ?? 0) ** 2);

    const eng = e.current;
    eng.fastWin.push(mag);  if (eng.fastWin.length > FAST_WIN) eng.fastWin.shift();
    eng.slowWin.push(mag);  if (eng.slowWin.length > SLOW_WIN) eng.slowWin.shift();
    if (eng.slowWin.length < SLOW_WIN) return;

    const fastAvg = eng.fastWin.reduce((a, b) => a + b) / FAST_WIN;
    const slowAvg = eng.slowWin.reduce((a, b) => a + b) / SLOW_WIN;
    const ratio   = fastAvg / (slowAvg + 0.001);

    const now = Date.now();

    // Rising edge: flag that we're above threshold
    if (!eng.above && ratio >= SENS_THRESHOLD) {
      eng.above = true;
    }
    // Falling edge: fire step
    else if (eng.above && ratio < SENS_THRESHOLD * 0.75) {
      eng.above = false;
      if (now - eng.lastStepMs >= MIN_STEP_MS) {
        eng.lastStepMs = now;
        eng.stepTimes.push(now);
        if (eng.stepTimes.length > 5) eng.stepTimes.shift();

        if (eng.stepTimes.length >= 2) {
          const intervals = eng.stepTimes.slice(1).map((t, i) => t - eng.stepTimes[i]);
          const avgInterval = intervals.reduce((a, b) => a + b) / intervals.length;
          const detected = Math.min(Math.max(60000 / avgInterval, 40), 160);
          eng.currentBPM = detected * STEP_LEAD;
          setBpm(Math.round(detected));
        }

        setSteps(s => s + 1);
        setIsFrozen(false);
      }
    }
  };

  // ── Metronome scheduler ────────────────────────────────────────────────────
  const scheduleBeat = () => {
    const eng = e.current;
    if (!eng.isRunning) return;

    const now   = Date.now();
    const gap   = eng.lastStepMs > 0 ? now - eng.lastStepMs : 0;
    const frozen = eng.lastStepMs > 0 && gap > FREEZE_MS;

    setIsFrozen(frozen);

    let bpmToPlay, buf;
    if (frozen) {
      bpmToPlay = Math.min(eng.currentBPM * (RESCUE_LEAD / STEP_LEAD), 160);
      buf = eng.sounds?.rescue;
    } else {
      bpmToPlay = Math.min(Math.max(eng.currentBPM, 40), 160);
      buf = eng.beatSide === 0 ? eng.sounds?.left : eng.sounds?.right;
      eng.beatSide = 1 - eng.beatSide;
    }

    if (buf) playBuf(audioCtx, buf);

    const interval = 60000 / (bpmToPlay || DEFAULT_BPM);
    setTimeout(scheduleBeat, interval);
  };

  // ── UI ─────────────────────────────────────────────────────────────────────
  return (
    <div className={`eesha-walk ${isFrozen ? "eesha-frozen" : ""}`}>

      <div className="eesha-status">
        {isFrozen ? "FREEZE DETECTED" : "WALKING"}
      </div>

      <div className="eesha-bpm-display">
        <span className="eesha-bpm-number">{bpm}</span>
        <span className="eesha-bpm-unit">BPM</span>
      </div>

      <div className="eesha-stat-row">
        <div className="eesha-stat">
          <span className="eesha-stat-value">{steps}</span>
          <span className="eesha-stat-label">Steps</span>
        </div>
        <div className="eesha-stat-divider" />
        <div className="eesha-stat">
          <span className="eesha-stat-value">
            {bpm === "--" ? "--" : Math.round(Number(bpm) * STEP_LEAD)}
          </span>
          <span className="eesha-stat-label">Playing</span>
        </div>
      </div>

      <button className="eesha-stop-btn" onClick={onStop}>
        STOP
      </button>
    </div>
  );
}
